mapper.select:
select
,
e.company_name,
u.real_name as handler_name
from biz_work_order w
left join biz_enterprise e on w.enterprise_id = e.id
left join sys_user u on w.handler_id = u.id

    AND w.is_deleted = 0

        AND w.enterprise_id = #{enterpriseId}


        AND w.order_no like concat('%', #{orderNo}, '%')


        AND w.title like concat('%', #{title}, '%')


        AND w.type = #{type}


        AND w.status = #{status}


        AND w.create_time >= #{startTime}


        AND w.create_time <= #{endTime}


ORDER BY w.create_time DESC

mapper.update:
update biz_work_order
title = #{title}, content = #{content}, contact_person = #{contactPerson}, contact_phone = #{contactPhone}, remark = #{remark}, status = #{status}, accept_time = #{acceptTime}, finish_time = #{finishTime}, handler_id = #{handlerId}, comment_text = #{commentText}, score = #{score}, images = #{images}, is_deleted = #{isDeleted}, update_time = NOW()
where id = #{id}
